-- Art. 15 — Non-Judicial Punishment
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_050', 'ETHICARA', 'MILITARY_STANDARD', 'US', '10 USC § 815 (UCMJ Art. 15)', 'Art. 15', 'Non-Judicial Punishment Procedures', 'Commanding officers may impose non-judicial punishment for minor offenses without a court-martial. Service member has right to refuse NJP and demand trial by court-martial (except aboard a vessel).', '["Commander determines offense is minor","Service member must be informed of rights","Right to demand trial by court-martial (except aboard vessel)","Right to consult with counsel before deciding","Right to present matters in defense/mitigation","Punishments limited by grade of imposing commander","Appeal to next superior authority within 5 days"]', '[{"section":"815(a)","description":"Authority to impose NJP"},{"section":"815(b)","description":"Punishments authorized by grade"},{"section":"815(c)","description":"Right to demand court-martial in lieu of NJP"},{"section":"815(e)","description":"Appeal of NJP"}]', '["NJP_record","page_11_entry","Article_15_proceedings","punishment_log","appeal_submission"]', '["usmc-military-standards-audit"]', 'JAGC / Military Courts', 0, 1, datetime('now'), datetime('now'));

-- Art. 31 — Self-Incrimination Rights (Military Miranda)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_051', 'ETHICARA', 'MILITARY_STANDARD', 'US', '10 USC § 831 (UCMJ Art. 31)', 'Art. 31', 'Self-Incrimination Rights — Military Miranda', 'Military equivalent of Miranda rights requiring warnings before interrogation. Broader than civilian Miranda — applies to any person subject to the UCMJ who suspects an offense has been committed, not only law enforcement.', '["Must inform suspect of nature of accusation","Must advise right to remain silent","Must warn that statements may be used as evidence","Applies to any person subject to UCMJ conducting questioning","Broader than civilian Miranda — not limited to custodial interrogation","Involuntary statements are inadmissible","Applies to both criminal investigators and commanders"]', '[{"section":"831(a)","description":"No compulsory self-incrimination"},{"section":"831(b)","description":"Required warnings before interrogation"},{"section":"831(d)","description":"Inadmissibility of involuntary statements"}]', '["interrogation_record","NCIS_report","CID_report","confession","sworn_statement","rights_waiver"]', '["usmc-military-standards-audit"]', 'JAGC / Military Courts', 0, 1, datetime('now'), datetime('now'));

-- Art. 32 — Preliminary Hearing Before Court-Martial
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_052', 'ETHICARA', 'MILITARY_STANDARD', 'US', '10 USC § 832 (UCMJ Art. 32)', 'Art. 32', 'Preliminary Hearing Before General Court-Martial', 'Requires a preliminary hearing before charges may be referred to a general court-martial. The hearing officer determines whether probable cause exists and recommends disposition.', '["Preliminary hearing required before general court-martial referral","Hearing officer must be a judge advocate (O-4 or above)","Accused has right to counsel at hearing","Accused may cross-examine witnesses","Hearing officer issues written report with recommendations","Convening authority not bound by recommendation","Limited to probable cause and jurisdiction determination"]', '[{"section":"832(a)","description":"Requirement for preliminary hearing"},{"section":"832(b)","description":"Hearing officer qualifications"},{"section":"832(c)","description":"Rights of the accused at hearing"},{"section":"832(d)","description":"Report and recommendations"}]', '["Article_32_hearing_report","charge_sheet","DD_Form_458","preliminary_hearing_transcript","counsel_request"]', '["usmc-military-standards-audit"]', 'JAGC / Military Courts', 0, 1, datetime('now'), datetime('now'));

-- Art. 120 — Sexual Assault Offenses
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_053', 'ETHICARA', 'MILITARY_STANDARD', 'US', '10 USC § 920 (UCMJ Art. 120)', 'Art. 120', 'Sexual Assault Offenses', 'Comprehensive military sexual assault statute covering rape, sexual assault, aggravated sexual contact, and abusive sexual contact. Mandatory minimum sentences and special victim counsel provisions.', '["Rape — sexual act by force or threat","Sexual assault — sexual act without consent","Aggravated sexual contact — sexual contact by force or threat","Abusive sexual contact — sexual contact without consent","Incapacity to consent (intoxication, sleep, unconsciousness)","Mandatory minimum sentences apply","Special Victims Counsel assigned to victim"]', '[{"section":"920(a)","description":"Rape — elements and penalties"},{"section":"920(b)","description":"Sexual assault — elements and penalties"},{"section":"920(c)","description":"Aggravated sexual contact"},{"section":"920(d)","description":"Abusive sexual contact"}]', '["SARC_report","NCIS_investigation","victim_statement","forensic_exam","restricted_report","unrestricted_report","court_martial_record"]', '["usmc-military-standards-audit"]', 'JAGC / Military Courts', 0, 1, datetime('now'), datetime('now'));

-- Art. 134 — General Article
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_054', 'ETHICARA', 'MILITARY_STANDARD', 'US', '10 USC § 934 (UCMJ Art. 134)', 'Art. 134', 'General Article — Conduct Prejudicial to Good Order and Discipline', 'Catch-all provision covering offenses not specifically enumerated in the UCMJ. Three clauses: prejudicial to good order and discipline, service-discrediting, and crimes and offenses not capital.', '["Clause 1: Conduct prejudicial to good order and discipline","Clause 2: Conduct of a nature to bring discredit upon the armed forces","Clause 3: Crimes and offenses not capital (federal assimilative crimes)","Must be conduct beyond mere technical violation","Includes enumerated offenses in MCM Part IV","Examples: adultery, fraternization, drunk and disorderly, communicating a threat"]', '[{"section":"934 Clause 1","description":"Prejudicial to good order and discipline"},{"section":"934 Clause 2","description":"Service-discrediting conduct"},{"section":"934 Clause 3","description":"Noncapital crimes assimilated from federal law"}]', '["charge_sheet","NJP_record","court_martial_record","command_investigation","counseling_record"]', '["usmc-military-standards-audit"]', 'JAGC / Military Courts', 0, 1, datetime('now'), datetime('now'));

-- Art. 86 — Absence Without Leave
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_055', 'ETHICARA', 'MILITARY_STANDARD', 'US', '10 USC § 886 (UCMJ Art. 86)', 'Art. 86', 'Absence Without Leave (AWOL/UA)', 'Prohibits absence without authority from unit, organization, or place of duty. Includes failure to go to appointed place of duty and going from appointed place of duty.', '["Failure to go to appointed place of duty at prescribed time","Going from appointed place of duty","Absence from unit/organization/place of duty without authority","Knowledge of appointed time/place not required if duty was reasonable","Aggravated by duration (over 30 days, terminated by apprehension)","Intent to avoid hazardous duty or shirk important service is separate offense"]', '[{"section":"886(1)","description":"Failure to go to appointed place of duty"},{"section":"886(2)","description":"Going from appointed place of duty"},{"section":"886(3)","description":"Absence without leave"}]', '["UA_muster_report","charge_sheet","page_11_entry","apprehension_record","NJP_record","court_martial_record"]', '["usmc-military-standards-audit"]', 'JAGC / Military Courts', 0, 1, datetime('now'), datetime('now'));

-- Art. 91 — Insubordinate Conduct Toward NCO
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_056', 'ETHICARA', 'MILITARY_STANDARD', 'US', '10 USC § 891 (UCMJ Art. 91)', 'Art. 91', 'Insubordinate Conduct Toward Warrant Officer, NCO, or Petty Officer', 'Prohibits striking, disobeying, or using contemptuous or disrespectful language toward a warrant officer, noncommissioned officer, or petty officer while that person is in the execution of their office.', '["Striking or assaulting warrant officer/NCO/PO","Willfully disobeying lawful order of warrant officer/NCO/PO","Treating with contempt or being disrespectful in language or deportment","Victim must be in execution of office","Accused must know victim is WO/NCO/PO","Order must be lawful and relate to military duty"]', '[{"section":"891(1)","description":"Striking or assaulting WO/NCO/PO"},{"section":"891(2)","description":"Willfully disobeying lawful order"},{"section":"891(3)","description":"Contemptuous or disrespectful language/deportment"}]', '["charge_sheet","incident_report","witness_statement","NJP_record","court_martial_record","counseling_record"]', '["usmc-military-standards-audit"]', 'JAGC / Military Courts', 0, 1, datetime('now'), datetime('now'));

-- Art. 92 — Failure to Obey Order or Regulation
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_057', 'ETHICARA', 'MILITARY_STANDARD', 'US', '10 USC § 892 (UCMJ Art. 92)', 'Art. 92', 'Failure to Obey Order or Regulation', 'Covers violation of general orders/regulations, failure to obey lawful orders, and dereliction of duty. One of the most commonly charged UCMJ articles.', '["Violation of general order or regulation","Failure to obey other lawful order","Dereliction in performance of duties (negligent or willful)","General order must be lawful and published/known","Other lawful order must be specific to accused","Dereliction requires knowledge of duties and failure to perform"]', '[{"section":"892(1)","description":"Violation of or failure to obey lawful general order or regulation"},{"section":"892(2)","description":"Failure to obey other lawful order"},{"section":"892(3)","description":"Dereliction of duty"}]', '["charge_sheet","general_order","SOP","NJP_record","counseling_record","court_martial_record","fitness_report"]', '["usmc-military-standards-audit"]', 'JAGC / Military Courts', 0, 1, datetime('now'), datetime('now'));

-- Art. 128 — Assault
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_eth_058', 'ETHICARA', 'MILITARY_STANDARD', 'US', '10 USC § 928 (UCMJ Art. 128)', 'Art. 128', 'Assault', 'Military assault statute covering simple assault, assault consummated by battery, aggravated assault (with dangerous weapon, means/force likely to produce death or grievous bodily harm), and assault on a child.', '["Simple assault — offer or attempt to do bodily harm with apparent present ability","Assault consummated by battery — unlawful force or violence applied","Aggravated assault with dangerous weapon","Aggravated assault with means likely to produce death or grievous bodily harm","Assault on child under 16","Specific intent not required for battery"]', '[{"section":"928(a)","description":"Simple assault"},{"section":"928(b)","description":"Assault consummated by a battery"},{"section":"928(c)","description":"Aggravated assault with dangerous weapon or means likely to cause death/GBH"}]', '["charge_sheet","incident_report","medical_record","witness_statement","NJP_record","court_martial_record","PMO_report"]', '["usmc-military-standards-audit"]', 'JAGC / Military Courts', 0, 1, datetime('now'), datetime('now'));


