-- LC § 201 — Final Wages on Discharge
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_080', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Lab. Code § 201', 'LC § 201', 'Final Wages on Discharge — Immediately Due', 'When an employer discharges an employee, all wages earned and unpaid at the time of discharge are immediately due and payable at the place of discharge.', '["All earned wages due immediately upon discharge","Payment at place of discharge","Applies to all forms of compensation earned","No grace period — immediately means immediately","Includes commissions if determinable","Employer cannot condition payment on return of property"]', '[{"section":"201(a)","description":"Immediate payment of wages upon discharge"},{"section":"201(b)","description":"Seasonal employees in specified industries — 72 hours"}]', '["final_paycheck","termination_record","wage_statement","discharge_notice"]', '["california-labor-employment-audit"]', 'California DLSE / Labor Commissioner', 1, 1, datetime('now'), datetime('now'));

-- LC § 202 — Final Wages on Quit
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_081', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Lab. Code § 202', 'LC § 202', 'Final Wages on Quit — Within 72 Hours', 'When an employee quits without giving 72 hours prior notice, wages are due within 72 hours. If 72 hours notice is given, wages are due at the time of quitting.', '["Wages due within 72 hours of quitting without notice","Wages due immediately if 72 hours notice given","Payment by mail permitted if employee requests","Singling out does not excuse late payment","Final wages must include all earned compensation"]', '[{"section":"202(a)","description":"72-hour payment window for voluntary quit without notice"},{"section":"202(a)","description":"Immediate payment when 72 hours notice given"}]', '["final_paycheck","resignation_letter","wage_statement","pay_record"]', '["california-labor-employment-audit"]', 'California DLSE / Labor Commissioner', 1, 1, datetime('now'), datetime('now'));

-- LC § 203 — Waiting Time Penalties
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_082', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Lab. Code § 203', 'LC § 203', 'Waiting Time Penalties — Up to 30 Days Wages', 'If an employer willfully fails to pay final wages on time, the employee''s wages continue as a penalty from the due date at the same rate of pay for up to 30 calendar days.', '["Penalty accrues at daily rate of pay","Maximum 30 calendar days of penalty wages","Willful failure — employer knew wages were due","Good faith dispute is a defense","Penalty calculated on daily rate, not hourly","Each day of non-payment is a separate violation"]', '[{"section":"203(a)","description":"Waiting time penalty — up to 30 days wages"},{"section":"203(b)","description":"Good faith dispute defense"}]', '["wage_claim","DLSE_complaint","penalty_calculation","final_pay_dispute"]', '["california-labor-employment-audit"]', 'California DLSE / Labor Commissioner', 1, 1, datetime('now'), datetime('now'));

-- LC § 227.3 — Vacation Pay on Termination
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_083', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Lab. Code § 227.3', 'LC § 227.3', 'Vacation Pay on Termination', 'Vested vacation time is treated as wages and must be paid out at the employee''s final rate of pay upon termination. Use-it-or-lose-it policies are prohibited in California.', '["Vested vacation is a form of wages","Must be paid at final rate of pay upon termination","Use-it-or-lose-it policies are illegal","Reasonable cap on accrual is permitted","Applies to termination, resignation, layoff, or death","No forfeiture of earned vacation time"]', '[{"section":"227.3","description":"Vacation wages payable on termination at final rate"}]', '["final_paycheck","vacation_accrual_record","employee_handbook","wage_claim"]', '["california-labor-employment-audit"]', 'California DLSE / Labor Commissioner', 1, 1, datetime('now'), datetime('now'));

-- LC § 1102.5 — Whistleblower Protection
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_084', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Lab. Code § 1102.5', 'LC § 1102.5', 'Whistleblower Protection', 'Prohibits employer retaliation against employees who report suspected violations of law to government or law enforcement, or who refuse to participate in illegal activity.', '["No retaliation for disclosing violation of law to government agency","No retaliation for disclosing violation to supervisor with authority to investigate","No retaliation for refusing to participate in illegal activity","No retaliation for reporting to person with authority over employee","Rebuttable presumption of retaliation if adverse action within 90 days","Civil penalties and reinstatement available"]', '[{"section":"1102.5(a)","description":"Cannot make rule preventing disclosure of violation"},{"section":"1102.5(b)","description":"Cannot retaliate for disclosure to government or authority"},{"section":"1102.5(c)","description":"Cannot retaliate for refusal to participate in illegal activity"},{"section":"1102.5(f)","description":"Civil penalties up to $10,000 per violation"}]', '["whistleblower_complaint","retaliation_claim","DLSE_complaint","termination_record","internal_report"]', '["california-labor-employment-audit"]', 'California DLSE / Labor Commissioner / Attorney General', 1, 1, datetime('now'), datetime('now'));

-- LC §§ 230-230.8 — Time Off Protections
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_085', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Lab. Code §§ 230-230.8', 'LC §§ 230-230.8', 'Time Off for Jury Duty, Court Appearances, DV/SA/Crime Victims', 'Comprehensive time-off protections for jury duty, court appearances, and victims of domestic violence, sexual assault, stalking, and crime.', '["Cannot discharge or discriminate for jury duty service","Cannot retaliate for court appearance as required by law","Time off for DV/SA/stalking victims to seek medical attention, services, counseling, safety planning","Time off for crime victims to attend judicial proceedings","Reasonable accommodation for DV/SA/stalking victims","Employer must maintain confidentiality of employee status"]', '[{"section":"230(a)","description":"Jury duty protection"},{"section":"230(b)","description":"Court appearance as crime victim protection"},{"section":"230.1","description":"Time off for DV/SA/stalking victims"},{"section":"230.2","description":"Time off for crime victims attending proceedings"},{"section":"230.5","description":"Employer cannot discriminate based on victim status"},{"section":"230.8","description":"Time off for school activities"}]', '["jury_duty_notice","court_subpoena","DV_restraining_order","victim_services_record","accommodation_request"]', '["california-labor-employment-audit"]', 'California DLSE / Labor Commissioner', 1, 1, datetime('now'), datetime('now'));

-- LC § 2802 — Employer Reimbursement of Necessary Expenses
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_086', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Lab. Code § 2802', 'LC § 2802', 'Employer Reimbursement of Necessary Expenses', 'Employer must indemnify employees for all necessary expenditures and losses incurred in direct consequence of the discharge of duties or employer direction.', '["Must reimburse all necessary expenditures incurred in discharge of duties","Must reimburse losses caused by employer direction","Includes cell phone, internet, mileage, tools, equipment","Applies even if employee does not submit expense report","Cannot require employees to bear business expenses","Interest accrues on unpaid reimbursements"]', '[{"section":"2802(a)","description":"Employer indemnification for necessary expenditures and losses"},{"section":"2802(b)","description":"Definition of necessary expenditures"},{"section":"2802(c)","description":"Applies to losses from employer-required actions"}]', '["expense_report","reimbursement_claim","wage_claim","cell_phone_policy","mileage_log"]', '["california-labor-employment-audit"]', 'California DLSE / Labor Commissioner', 1, 1, datetime('now'), datetime('now'));

-- LC § 98.6 — Retaliation for Filing Labor Claim
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_087', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Lab. Code § 98.6', 'LC § 98.6', 'Retaliation for Filing Labor Claim or Complaint', 'Prohibits employer retaliation against employees who file or threaten to file labor claims, complaints, or who exercise rights under the Labor Code.', '["Cannot discharge or discriminate for filing wage claim","Cannot retaliate for complaints to Labor Commissioner","Cannot retaliate for exercising any right under Labor Code","Rebuttable presumption of retaliation within 90 days of protected activity","Penalties include reinstatement, back pay, and civil penalty up to $10,000","Labor Commissioner may prosecute action on behalf of employee"]', '[{"section":"98.6(a)","description":"Prohibited retaliation for filing complaints or exercising rights"},{"section":"98.6(b)","description":"Rebuttable presumption of retaliation"},{"section":"98.6(c)","description":"Penalties and remedies"}]', '["DLSE_complaint","wage_claim","retaliation_complaint","termination_record","adverse_action_notice"]', '["california-labor-employment-audit"]', 'California DLSE / Labor Commissioner', 1, 1, datetime('now'), datetime('now'));

-- Cal. Gov. Code §§ 12940-12951 (FEHA Employment)
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_reg_088', 'REGULIS', 'STATE_STATUTE', 'CA', 'Cal. Gov. Code §§ 12940-12951 (FEHA)', 'FEHA Employment', 'Fair Employment and Housing Act — Employment Discrimination Provisions', 'California''s primary employment discrimination statute prohibiting discrimination, harassment, and retaliation based on protected characteristics. Applies to employers with 5+ employees (harassment provisions apply to all employers).', '["Discrimination prohibited based on race, color, religion, sex, gender, sexual orientation, marital status, national origin, ancestry, disability, medical condition, age (40+), genetic information, military/veteran status","Harassment prohibited for all employers regardless of size","Employer must take reasonable steps to prevent discrimination and harassment","Reasonable accommodation required for disability and religious beliefs","Interactive process required for disability accommodation","Retaliation prohibited for opposing discrimination or filing complaint"]', '[{"section":"12940(a)","description":"Unlawful employment practices — discrimination"},{"section":"12940(j)","description":"Harassment — applies to all employers"},{"section":"12940(k)","description":"Failure to prevent discrimination/harassment"},{"section":"12940(m)","description":"Failure to accommodate disability"},{"section":"12940(n)","description":"Failure to engage in interactive process"},{"section":"12945.2","description":"CFRA leave provisions"},{"section":"12951","description":"Right to workplace lactation accommodation"}]', '["DFEH_complaint","EEOC_charge","right_to_sue_letter","accommodation_request","interactive_process_record","harassment_complaint","termination_record"]', '["california-labor-employment-audit"]', 'DFEH (now CRD) / Superior Court', 1, 1, datetime('now'), datetime('now'));


