-- 12 CFR Part 1030 (Reg DD) — Truth in Savings
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_030', 'FISCARA', 'FEDERAL_REGULATION', 'US', '12 CFR Part 1030 (Regulation DD)', 'Reg DD', 'Truth in Savings Act — Regulation DD', 'Requires depository institutions to provide uniform disclosures about deposit accounts to enable consumers to make meaningful comparisons. Covers interest rates, fees, and account terms.', '["Disclose APY and interest rate uniformly","Disclose fees and terms before account opening","Provide periodic statements with interest earned and fees charged","Advertising must not be misleading","Balance computation method must be disclosed","Notice required before adverse changes to account terms"]', '[{"section":"1030.3","description":"General disclosure requirements"},{"section":"1030.4","description":"Account disclosures — rates, fees, terms"},{"section":"1030.5","description":"Subsequent disclosures — change in terms notice"},{"section":"1030.6","description":"Periodic statement disclosures"},{"section":"1030.8","description":"Advertising requirements"},{"section":"1030.11","description":"Additional disclosure for overdraft services"}]', '["account_disclosure","deposit_agreement","periodic_statement","fee_schedule","change_in_terms_notice","savings_account_ad"]', '["banking-financial-document-audit"]', 'CFPB', 1, 1, datetime('now'), datetime('now'));

-- 15 USC § 1693g — Consumer Liability for Unauthorized EFTs
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_031', 'FISCARA', 'FEDERAL_STATUTE', 'US', '15 USC § 1693g', 'EFTA § 909', 'Consumer Liability Limits for Unauthorized Electronic Fund Transfers', 'Establishes tiered consumer liability limits for unauthorized EFTs based on timing of consumer notification. Maximum $50 if reported within 2 business days, $500 within 60 days, unlimited thereafter.', '["$50 maximum liability if reported within 2 business days of learning of loss/theft","$500 maximum liability if reported within 60 days of transmittal of statement","Unlimited liability if not reported within 60 days of statement","Financial institution bears burden of proving consumer liability","Extenuating circumstances may extend reporting deadlines","Institution must prove access device was used and consumer received required disclosures"]', '[{"section":"1693g(a)","description":"Tiered liability limits — $50/$500/unlimited"},{"section":"1693g(b)","description":"Burden of proof on financial institution"},{"section":"1693g(c)","description":"Definition of unauthorized EFT"},{"section":"1693g(d)","description":"Relation to state law"}]', '["unauthorized_transaction_report","EFT_dispute","bank_statement","debit_card_fraud_claim","Reg_E_dispute","provisional_credit_notice"]', '["banking-financial-document-audit"]', 'CFPB', 1, 1, datetime('now'), datetime('now'));

-- Dodd-Frank Act — CFPB Establishment
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_032', 'FISCARA', 'FEDERAL_STATUTE', 'US', 'Dodd-Frank Wall Street Reform Act, 12 USC §§ 5481-5603 (Title X)', 'Dodd-Frank Title X', 'Consumer Financial Protection Act — CFPB Establishment and Authority', 'Title X of Dodd-Frank establishes the Consumer Financial Protection Bureau (CFPB) with authority to regulate consumer financial products and services, enforce federal consumer financial law, and prohibit unfair, deceptive, or abusive acts or practices (UDAAP).', '["CFPB has exclusive rulemaking authority for enumerated consumer laws","Prohibits unfair, deceptive, or abusive acts or practices (UDAAP)","Supervises banks with assets over $10B and nonbank financial companies","Receives and investigates consumer complaints","Can bring enforcement actions with civil money penalties","State attorneys general may enforce CFPB rules","Consumer financial education mandate"]', '[{"section":"5531","description":"Prohibition of UDAAP — unfair, deceptive, or abusive acts/practices"},{"section":"5536","description":"Prohibited acts — violations and enforcement"},{"section":"5552","description":"State attorney general enforcement of CFPB rules"},{"section":"5565","description":"Relief available — restitution, disgorgement, civil penalties"},{"section":"5481","description":"Definitions — covered person, service provider, consumer financial product"}]', '["CFPB_complaint","enforcement_action","consent_order","UDAAP_analysis","supervisory_exam","consumer_complaint"]', '["banking-financial-document-audit"]', 'CFPB', 1, 1, datetime('now'), datetime('now'));

-- Cal. Fin. Code §§ 1000-1706 — California Financial Code Banking Operations
INSERT OR IGNORE INTO governing_standards (id, citizen_name, standard_type, jurisdiction, citation, short_cite, title, description, requirements, key_sections, document_types, skill_slugs, enforcement_body, private_right_of_action, is_active, created_at, updated_at)
VALUES
('std_fis_033', 'FISCARA', 'STATE_STATUTE', 'CA', 'Cal. Fin. Code §§ 1000-1706', 'CFC §§ 1000-1706', 'California Financial Code — Banking Operations', 'California state banking law governing the organization, operation, and regulation of commercial banks, savings banks, and trust companies operating in California.', '["DFPI licensing and supervision of state-chartered banks","Minimum capital requirements for bank formation","Fiduciary duties of bank officers and directors","Restrictions on insider transactions and conflicts of interest","Examination and audit authority of Commissioner","Assessment of fees and penalties for noncompliance","Consumer protection provisions for deposit accounts"]', '[{"section":"1000-1017","description":"General provisions and definitions"},{"section":"1020-1042","description":"Organization and incorporation of banks"},{"section":"1100-1107","description":"Officers, directors, and fiduciary duties"},{"section":"1200-1236","description":"Powers and operations of banks"},{"section":"1500-1563","description":"Savings bank provisions"},{"section":"1600-1706","description":"Trust company operations and regulation"}]', '["bank_charter","DFPI_examination","audit_report","compliance_filing","trust_agreement","bank_operations_manual"]', '["banking-financial-document-audit"]', 'California DFPI (Department of Financial Protection and Innovation)', 0, 1, datetime('now'), datetime('now'));
